import { Component, OnInit, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { DishService } from '../../services/Piatti/dish.service';
import { IngredientService } from '../../services/Piatti/ingredient.service';
import { LoadingService } from '../../services/Base/loading.service';
import { Category, Dish, Ingredient } from '../../models';
import { CategoryService } from '../../services/Piatti/category.service';
import { MenuManagementService } from '../../services/Piatti/menu-management.service';
import { MenuDishService } from '../../services/Piatti/menu-dish.service';
import { LucideAngularModule } from 'lucide-angular';

export interface DishIngredientComposition {
  ingredient_id: string;
  quantity: number;
  cost: number;
  unit_symbol?: string;
  recipe_notes?: string;
}

export interface IngredientComposition {
  id?: string;
  name: string;
  quantity: number;
  unit: string;
  notes?: string;
  recipe_notes?: string; 
}

@Component({
  selector: 'app-recipe',
  templateUrl: './recipe.html',
  styleUrls: ['./recipe.css'],
  standalone: true,
  imports: [CommonModule, FormsModule, LucideAngularModule]
})
export class Recipe implements OnInit {
  private dishService = inject(DishService);
  private ingredientService = inject(IngredientService);
  private loadingService = inject(LoadingService);
  private categoryService = inject(CategoryService);
  private menuService = inject(MenuManagementService);
  private menuDishService = inject(MenuDishService);

  recipeInstructions: string = '';
  preparationTime: number = 15;
  allIngredients: Ingredient[] = [];

  dishes: Dish[] = [];
  filteredDishes: Dish[] = [];
  
  // variabili per le categorie
  categories: Category[] = [];
  categoryFilter = 'all'; // Per il filtro

  // variabili per i menu
  menus: any[] = [];
  menuFilter = 'all'; // 'all', 'no_menu', o menuId specifico
  menuDishes: any[] = []; // Associazione tra menu e piatti
  dishMenuMap: Map<string, string[]> = new Map(); // Mappa: dishId -> array di menuId

  // Modal states
  selectedDish: Dish | null = null;
  showEditModal = false;
  showDeleteConfirm = false;
  dishToDelete: Dish | null = null;

  // Mappa per le note temporanee durante l'editing
  ingredientNotes: { [ingredientId: string]: string } = {};

  // AGGIUNTA: Mappa per tenere traccia degli ingredienti con note attivate
  ingredientNotesEnabled: { [ingredientId: string]: boolean } = {};

  // Search and filter
  searchTerm = '';
  statusFilter = 'all';

  ngOnInit() {
    this.loadIngredients();
    this.loadDishes();
    this.loadCategories();
    this.loadMenusAndAssociations(); 
  }

  async loadIngredients() {
    await this.ingredientService.loadIngredients();
    this.ingredientService.data$.subscribe(ingredients => {
      this.allIngredients = ingredients;
    });
  }

  async loadDishes() {
    this.loadingService.start();
    try {
      await this.dishService.loadDishes();
      this.dishService.data$.subscribe(dishes => {
        this.dishes = dishes;
        this.applyFilters();
        this.loadingService.stop();
      });
    } catch (error) {
      this.loadingService.stop();
      console.error('Error loading dishes:', error);
    }
  }

  async loadCategories() {
    await this.categoryService.loadData();
    this.categoryService.data$.subscribe(categories => {
      this.categories = categories;
    });
  }

  getCategoryName(categoryId: string | null): string {
    if (!categoryId) return 'Nessuna categoria';
    
    const category = this.categories.find(c => c.id === categoryId);
    return category ? category.name : 'Categoria non trovata';
  }

  async loadMenusAndAssociations() {
    try {
      // Carica i menu
      await this.menuService.loadData();
      this.menuService.data$.subscribe(menus => {
        this.menus = menus.filter(menu => menu.is_active); // Solo menu attivi
      });

      // Carica le associazioni menu-piatti
      await this.menuDishService.loadData();
      this.menuDishService.data$.subscribe(menuDishes => {
        this.menuDishes = menuDishes.filter(md => md.is_active); // Solo associazioni attive
        this.buildDishMenuMap(); // Costruisci la mappa
      });
    } catch (error) {
      console.error('Error loading menus:', error);
    }
  }

  // AGGIUNGI questo metodo per costruire la mappa dish->menu
  private buildDishMenuMap() {
    const map = new Map<string, string[]>();
    
    this.menuDishes.forEach(menuDish => {
      if (!menuDish.is_active || !menuDish.dish_id) return;
      
      const dishId = menuDish.dish_id;
      if (!map.has(dishId)) {
        map.set(dishId, []);
      }
      map.get(dishId)!.push(menuDish.menu_id);
    });
    
    this.dishMenuMap = map;
  }

  // AGGIUNGI questo metodo per ottenere i nomi dei menu di un piatto
  getMenuNamesForDish(dishId: string): string[] {
    const menuIds = this.dishMenuMap.get(dishId) || [];
    return menuIds.map(menuId => {
      const menu = this.menus.find(m => m.id === menuId);
      return menu ? menu.name : 'Menu sconosciuto';
    });
  }

  // AGGIUNGI questo metodo per verificare se un piatto è in un menu specifico
  isDishInMenu(dishId: string, menuId: string): boolean {
    const menuIds = this.dishMenuMap.get(dishId);
    return menuIds ? menuIds.includes(menuId) : false;
  }

  // FILTERS AND SEARCH
  applyFilters() {
    let filtered = this.dishes;

    // Filtro per stato (esistente)
    if (this.statusFilter !== 'all') {
      filtered = filtered.filter(dish => dish.status === this.statusFilter);
    }

    // Filtro per categoria (aggiunto precedentemente)
    if (this.categoryFilter !== 'all') {
      filtered = filtered.filter(dish => dish.category_id === this.categoryFilter);
    }

    // AGGIUNGI filtro per menu
    if (this.menuFilter !== 'all') {
      if (this.menuFilter === 'no_menu') {
        // Piatti senza menu (non presenti in nessun menu attivo)
        filtered = filtered.filter(dish => {
          const menuIds = this.dishMenuMap.get(dish.id);
          return !menuIds || menuIds.length === 0;
        });
      } else {
        // Piatti in un menu specifico
        filtered = filtered.filter(dish => 
          this.isDishInMenu(dish.id, this.menuFilter)
        );
      }
    }

    // Filtro di ricerca (esistente)
    if (this.searchTerm) {
      const term = this.searchTerm.toLowerCase();
      filtered = filtered.filter(dish =>
        dish.name.toLowerCase().includes(term) ||
        dish.description?.toLowerCase().includes(term) ||
        this.hasIngredientWithName(dish, term)
      );
    }

    this.filteredDishes = filtered;
  }

  onMenuFilterChange() {
    this.applyFilters();
  }


  private hasIngredientWithName(dish: Dish, term: string): boolean {
    if (!dish || !dish.ingredients_composition) return false;
    
    return dish.ingredients_composition.some((ingredientData: DishIngredientComposition) => {
      const ingredientName = this.getIngredientName(ingredientData).toLowerCase();
      return ingredientName.includes(term);
    });
  }

  onCategoryFilterChange() {
    this.applyFilters();
  }

  onSearchChange() {
    this.applyFilters();
  }

  onStatusFilterChange() {
    this.applyFilters();
  }

  // MODAL MANAGEMENT
  openEditModal(dish: Dish) {
    this.selectedDish = { 
      ...dish,
      ingredients_composition: dish.ingredients_composition ? 
        [...dish.ingredients_composition] : []
    };
    
    this.recipeInstructions = dish.recipe_instructions || '';
    this.preparationTime = dish.preparation_time || 15;
    
    this.initializeIngredientNotes();
    
    this.showEditModal = true;
  }

  private initializeIngredientNotes() {
    this.ingredientNotes = {};
    this.ingredientNotesEnabled = {}; // Reset anche per le checkbox
    
    if (this.selectedDish?.ingredients_composition) {
      this.selectedDish.ingredients_composition.forEach((ingredient: DishIngredientComposition) => {
        if (ingredient.ingredient_id) {
          this.ingredientNotes[ingredient.ingredient_id] = ingredient.recipe_notes || '';
          // Se esistono già delle note, allora la checkbox è attivata
          this.ingredientNotesEnabled[ingredient.ingredient_id] = !!ingredient.recipe_notes;
        }
      });
    }
  }

  closeEditModal() {
    this.selectedDish = null;
    this.showEditModal = false;
    this.ingredientNotes = {};
    this.ingredientNotesEnabled = {}; // Reset anche per le checkbox
  }

  // RECIPE MANAGEMENT
  async saveRecipe(): Promise<void> {
  if (!this.selectedDish || !this.canSaveRecipe()) {
    console.log('Niente da salvare o piatto non selezionato');
    return;
  }

    this.loadingService.start();
    try {
      const updatedComposition = this.selectedDish.ingredients_composition?.map((ingredient: DishIngredientComposition) => {
        // Se le note non sono abilitate per questo ingrediente, salviamo stringa vuota
        const notes = this.ingredientNotesEnabled[ingredient.ingredient_id] ? 
          (this.ingredientNotes[ingredient.ingredient_id] || '') : '';

        return {
          ...ingredient,
          recipe_notes: notes
        };
      });

      const updates = {
        recipe_instructions: this.recipeInstructions,
        preparation_time: this.preparationTime,
        ingredients_composition: updatedComposition
      };

      const success = await this.dishService.updateDish(this.selectedDish.id, updates);
      if (success) {
        await this.dishService.loadDishes();
        this.closeEditModal();
      } else {
        console.error('Error saving recipe');
      }
    } catch (error) {
      console.error('Error saving recipe:', error);
    } finally {
      this.loadingService.stop();
    }
  }

  // Metodo per aggiornare le note di un ingrediente
  updateIngredientNotes(ingredientId: string, notes: string): void {
    this.ingredientNotes[ingredientId] = notes;
  }

  // Metodo per ottenere le note di un ingrediente
  getIngredientNotes(ingredientId: string): string {
    return this.ingredientNotes[ingredientId] || '';
  }

  // AGGIUNTA: Metodo per gestire il toggle della checkbox
  toggleIngredientNotes(ingredientId: string, enabled: boolean): void {
    this.ingredientNotesEnabled[ingredientId] = enabled;
    // Se disattiviamo le note, puliamo il contenuto
  //  if (!enabled) {
  //    this.ingredientNotes[ingredientId] = '';
  //  }
  }

  // AGGIUNTA: Metodo per verificare se le note sono abilitate per un ingrediente
  areNotesEnabled(ingredientId: string): boolean {
    return this.ingredientNotesEnabled[ingredientId] || false;
  }

  navigateToFoodCostBuilder(): void {
    console.log('Navigate to food cost builder for dish:', this.selectedDish?.id);
  }

  navigateToFoodCostBuilderFromTable(dish: Dish): void {
    console.log('Navigate to food cost builder for dish from table:', dish.id);
  }

canSaveRecipe(): boolean {
  // Versione semplificata:
  // Può salvare se c'è almeno UNA di queste cose:
  
  // 1. Istruzioni generali
  if (this.recipeInstructions && this.recipeInstructions.trim().length > 0) {
    return true;
  }
  
  // 2. Check di sicurezza: se non c'è un piatto selezionato
  if (!this.selectedDish?.ingredients_composition) {
    return false;
  }
  
  // 3. Controlla se ci sono note abilitate per gli ingredienti
  return this.selectedDish.ingredients_composition.some((ingredient: DishIngredientComposition) => {
    // Se c'è almeno un ingrediente con checkbox attivata, può salvare
    return this.ingredientNotesEnabled[ingredient.ingredient_id];
  });
}

  cancelDelete() {
    this.dishToDelete = null;
    this.showDeleteConfirm = false;
  }

  async deleteDish() {
    if (this.dishToDelete) {
      this.loadingService.start();
      try {
        const success = await this.dishService.updateDish(this.dishToDelete.id, {
          ingredients_composition: []
        });
        
        if (success) {
          await this.loadDishes();
        }
      } catch (error) {
        console.error('Error deleting dish:', error);
      } finally {
        this.loadingService.stop();
        this.cancelDelete();
      }
    }
  }

  // UTILITIES
  getStatusColor(status: string): string {
    const colorMap: { [key: string]: string } = {
      'available': 'success',
      'unavailable': 'warning',
      'out_of_stock': 'danger'
    };
    return colorMap[status] || 'secondary';
  }

  getStatusText(status: string): string {
    const textMap: { [key: string]: string } = {
      'available': 'Disponibile',
      'unavailable': 'Non Disponibile',
      'out_of_stock': 'Esaurito'
    };
    return textMap[status] || status;
  }

  getTotalIngredients(dish: Dish): number {
    if (!dish || !dish.ingredients_composition) return 0;
    return dish.ingredients_composition.length;
  }

  // METODI HELPER PER GESTIRE GLI INGREDIENTI
  getIngredientName(ingredientData: DishIngredientComposition): string {
    if (!ingredientData.ingredient_id) return 'Ingrediente sconosciuto';
    
    const foundIngredient = this.allIngredients.find(ing => ing.id === ingredientData.ingredient_id);
    return foundIngredient?.name || 'Ingrediente non trovato';
  }

  getIngredientQuantity(ingredientData: DishIngredientComposition): number {
    return ingredientData.quantity || 0;
  }

  getIngredientUnit(ingredientData: DishIngredientComposition): string {
    return ingredientData.unit_symbol || '';
  }

  getIngredientCost(ingredientData: DishIngredientComposition): number {
    return ingredientData.cost || 0;
  }

  getFullIngredient(ingredientData: DishIngredientComposition): Ingredient | null {
    if (!ingredientData.ingredient_id) return null;
    return this.allIngredients.find(ing => ing.id === ingredientData.ingredient_id) || null;
  }

  getSavedIngredientNotes(ingredientData: DishIngredientComposition): string {
    return ingredientData.recipe_notes || '';
  }

// Metodo per contare le note abilitate
getEnabledNotesCount(): number {
  if (!this.selectedDish?.ingredients_composition) return 0;
  
  return this.selectedDish.ingredients_composition.filter((ingredient: DishIngredientComposition) => 
    this.ingredientNotesEnabled[ingredient.ingredient_id]
  ).length;
}


}